        /// <summary>
        /// 去读样式
        /// </summary>
        /// <param name="worksheet"></param>
        /// <returns></returns>
        public static List<CellStyle> ReadCellStyle(ExcelWorksheet worksheet)
        {
            var res = new List<CellStyle>();

            var cells = worksheet.Cells;

            foreach (var cell in cells)
            {
                var style = new CellStyle();
                style.StartRow = cell.Start.Row;
                style.StartCol = cell.Start.Column;
                style.EndRow = cell.End.Row;
                style.EndCol = cell.End.Column;
                style.Font = cell.Style.Font.Name;
                var tempColor = cell.Style.Font.Color.Rgb;

                if ( string.IsNullOrEmpty(tempColor) || tempColor.Length < 2)
                {
                    style.FontColor = "#000000";
                }
                else
                {
                    style.FontColor = "#" + tempColor.Substring(2);
                }

                style.Size = (int)cell.Style.Font.Size;
                style.UseBold = cell.Style.Font.Bold;
                style.UseItalic = cell.Style.Font.Italic;
                style.UseUnderLine = cell.Style.Font.UnderLine;
                style.UseStrike = cell.Style.Font.Strike;
                style.UseWrapText = cell.Style.WrapText;
                style.HorizontalAlignment = cell.Style.HorizontalAlignment.ToString();
                style.VerticalAlignment = cell.Style.VerticalAlignment.ToString();

                res.Add(style);
            }

            return res;
        }

