        /// <summary>
        /// 读取合并单元格
        /// </summary>
        /// <param name="worksheet"></param>
        /// <returns></returns>
        public static List<RangeMerge> ReadMerges(ExcelWorksheet worksheet)
        {
            var mergedCells = worksheet.MergedCells;
            var mergeList = new List<RangeMerge>();
            foreach (var address in mergedCells)  //string  A10:C10 这个式样的
            {
                var range = worksheet.Cells[address];
                mergeList.Add(new RangeMerge()
                {
                    IsMerged = true,
                    StartRow = range.Start.Row,
                    StartCol = range.Start.Column,
                    EndRow = range.End.Row,
                    EndCol = range.End.Column
                });
            }
            return mergeList;
        }
