                border.StartRow = cell.Start.Row;
                border.StartCol = cell.Start.Column;
                border.EndRow = cell.End.Row;
                border.EndCol = cell.End.Column;
                border.StyleName_Top = cell.Style.Border.Top.Style.ToString();
                border.StyleName_Bottom = cell.Style.Border.Bottom.Style.ToString();
