                border.StyleName_Right = cell.Style.Border.Right.Style.ToString();

                border.BorderColor_Top = LookupColor(cell.Style.Border.Top.Color.Rgb);
                border.BorderColor_Bottom = LookupColor(cell.Style.Border.Bottom.Color.Rgb);
                border.BorderColor_Left = LookupColor(cell.Style.Border.Left.Color.Rgb);
                border.BorderColor_Right = LookupColor(cell.Style.Border.Right.Color.Rgb);

                list.Add(border);
            }
            return list;
        }

        private static string LookupColor(string rgb)
