        /// <param name="BorderStyle"></param>
        /// <returns></returns>
        public static ExcelBorderStyle CastBorderStyleFromStr(string BorderStyle)
        {
            switch (BorderStyle)
            {
                case "None":
                    return ExcelBorderStyle.None;
                case "Hair":
                    return ExcelBorderStyle.Hair;
                case "Dotted":
                    return ExcelBorderStyle.Dotted;
                case "DashDot":
                    return ExcelBorderStyle.DashDot;
                case "Thin":
                    return ExcelBorderStyle.Thin;
                case "DashDotDot":
                    return ExcelBorderStyle.DashDotDot;
                case "Dashed":
                    return ExcelBorderStyle.Dashed;
                case "MediumDashDotDot":
                    return ExcelBorderStyle.MediumDashDotDot;
                case "MediumDashed":
                    return ExcelBorderStyle.MediumDashed;
                case "MediumDashDot":
                    return ExcelBorderStyle.MediumDashDot;
                case "Thick":
                    return ExcelBorderStyle.Thick;
                case "Medium":
                    return ExcelBorderStyle.Medium;
                case "Double":
                    return ExcelBorderStyle.Double;
                default:
                    return ExcelBorderStyle.None;
            }
        }


        /// <summary>
        /// 颜色，文本转System.Drawing.Color
        /// </summary>
        /// <param name="ColorCode"></param>
        /// <returns></returns>
        public static Color CastColorFromStr(string ColorCode)
        {
            if (!ColorCode.StartsWith("#"))
            {
                return Color.Black;
            }
            if (ColorCode.Length != 7 &&
                ColorCode.Length != 9)
            {
                return Color.Black;
            }

            var arr = ColorCode.ToCharArray();
            var r = "00";
            var g = "00";
            var b = "00";
            var a = "00";

            for (int i = 0; i < arr.Length; i++)
            {
                if (i == 1 || i == 2)
                {
                    r += arr[i];
                }
                if (i == 3 || i == 4)
                {
                    g += arr[i];
                }
                if (i == 5 || i == 6)
                {
                    b += arr[i];
                }
                if (i == 7 || i == 8)
                {
                    a += arr[i];
                }
            }

            int rr = Convert.ToInt32(r, 16);
            int gg = Convert.ToInt32(g, 16);
            int bb = Convert.ToInt32(b, 16);
            int aa = Convert.ToInt32(a, 16);

            return Color.FromArgb(aa, rr, gg, bb);
        }
    }
